          Logout
        </button>
      </div>
    </header>

    <div class="dashboard-grid">
      <aside class="side-panel">
        <div class="card post-card">
          <h2 class="card-title">Post New Internship</h2>
          <div class="form-group">
            <input class="input-field" placeholder="Role Title" [(ngModel)]="title" />
            <input class="input-field" placeholder="Location" [(ngModel)]="location" />
            <input class="input-field" placeholder="CTC" [(ngModel)]="ctc" />
            <input class="input-field" placeholder="Company" [(ngModel)]="companyName" />
            <textarea class="input-field" placeholder="Detailed Description" rows="3" [(ngModel)]="description"></textarea>

            <div class="upload-container">
              <label class="label-small">JD Attachment (PDF)</label>
              <input type="file" (change)="onPdfSelected($event)" (focus)="pausePolling()" (blur)="resumePolling()" />
              <div class="btn-group-row">
                <button (click)="handlePdfUpload()" class="btn-outline">Upload PDF</button>
                <button *ngIf="pdfUploaded" (click)="handlePost()" class="btn-primary">Post Internship</button>
              </div>
            </div>
          </div>
        </div>

        <h3 class="card-title" style="margin-top:20px">Active Postings</h3>
        <div class="card list-card">
          <div *ngFor="let i of internships" class="list-item-job">
            <div class="job-info">
              <h4>{{i.title}}</h4>
              <p>{{i.companyName}} • {{i.location}}</p>
            </div>
            <button class="btn-delete" (click)="handleDelete(i.id)">
               <svg width="16" height="16" fill="currentColor" viewBox="0 0 16 16"><path d="M5.5 5.5A.5.5 0 0 1 6 6v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm2.5 0a.5.5 0 0 1 .5.5v6a.5.5 0 0 1-1 0V6a.5.5 0 0 1 .5-.5zm3 .5a.5.5 0 0 0-1 0v6a.5.5 0 0 0 1 0V6z"/><path fill-rule="evenodd" d="M14.5 3a1 1 0 0 1-1 1H13v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V4h-.5a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1H6a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1h3.5a1 1 0 0 1 1 1v1z"/></svg>
            </button>
          </div>
        </div>
      </aside>

      <section class="main-pipeline">
        <h2 class="card-title">Candidate Management Pipeline</h2>

        <div *ngFor="let app of applications" class="candidate-card">
          <div class="candidate-header">
            <div class="cand-info">
              <span class="cand-name">{{app.candidateName}}</span>
              <span class="status-badge">{{app.status?.replace('_', ' ')}}</span>
              <p class="cand-meta">{{app.email}} | {{app.phone}}</p>
            </div>
            <button class="btn-details" (click)="selectedCandidate = app">View Details</button>
          </div>

          <div class="journey-flow">
            <div class="journey-item">
              <span class="j-label">Online Test</span>
              <span class="j-val text-success">✓ Cleared</span>
            </div>
            <div class="journey-item" *ngIf="app.l1Date">
              <span class="j-label">L1 Interview</span>
              <span class="j-val">{{formatDate(app.l1Date)}} | {{getInterviewerName(app.l1InterviewerId)}}</span>
              <p class="res-text">Result: <b>{{app.l1Result || 'Pending'}}</b></p>
            </div>
            <div class="journey-item" *ngIf="app.hrDate">
              <span class="j-label">HR Round</span>
              <span class="j-val">{{formatDate(app.hrDate)}} | {{app.hrMode}}</span>
              <p class="res-text">Result: <b>{{app.hrResult || 'Pending'}}</b></p>
            </div>
          </div>

          <div class="actions-section">
            <div *ngIf="showScheduleOptions(app)" class="scheduling-block">
              <div class="input-grid">
                <input type="date" class="input-sm" [ngModel]="getScheduleValue(app.id,'date')" (ngModelChange)="setScheduleValue(app.id,'date',$event)" />
                <input type="time" class="input-sm" [ngModel]="getScheduleValue(app.id,'time')" (ngModelChange)="setScheduleValue(app.id,'time',$event)" />
                <select class="input-sm" [ngModel]="getScheduleValue(app.id,'mode')" (ngModelChange)="setScheduleValue(app.id,'mode',$event)">
                  <option value="">Mode</option><option value="ONLINE">Online</option><option value="OFFLINE">Offline</option>
                </select>
                <select *ngIf="app.status !== 'HR_PENDING'" class="input-sm" [ngModel]="getScheduleValue(app.id,'interviewerId')" (ngModelChange)="setScheduleValue(app.id,'interviewerId',$event)">
                  <option value="">Interviewer</option>
                  <option *ngFor="let iv of interviewerOptionsForApp(app)" [value]="iv.id">{{ iv.name }}</option>
                </select>
              </div>
              <button (click)="scheduleInterview(app.id, app.status)" class="btn-primary-sm">{{ scheduleLabel(app) }}</button>
            </div>

            <div *ngIf="app.interviewStatus === 'HR_SCHEDULED' && app.status !== 'SELECTED' && app.status !== 'REJECTED'" class="decision-block">
              <button (click)="updateHrResult(app.id, 'HR_PASSED')" class="btn-select">Select for Offer</button>
              <button (click)="updateHrResult(app.id, 'HR_FAILED')" class="btn-reject">Reject</button>
            </div>

            <div *ngIf="app.status === 'SELECTED' || app.status === 'OFFER_PENDING' || app.signedOfferLetter" class="post-selection-block">
              <div *ngIf="!app.offerLetterFile" class="upload-box">
                <input type="file" (change)="handleOfferFileChange(app.id, $event)" />
                <button (click)="uploadOfferLetter(app.id)" class="btn-primary-sm">Send Offer Letter</button>
              </div>

              <div *ngIf="app.signedOfferLetter" class="onboarding-box">
                <div class="alert-success">Signed Offer Received!</div>
                <div class="btn-group-row" style="margin-top:10px">
                  <button class="btn-primary-sm" (click)="router.navigate(['/hr/onboarding', app.email])">Process Onboarding</button>
                  <button *ngIf="!employeeExists(app.email)" class="btn-dark-sm" (click)="router.navigate(['/hr/create-employee', app.email], { state: { applicationId: app.id } })">Create Employee Record</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    </div>

    <div *ngIf="selectedCandidate" class="details-overlay">
      <div class="overlay-content">
        <div class="overlay-header">
          <h3>Application Dossier</h3>
          <button (click)="selectedCandidate=null" class="btn-close">&times;</button>
        </div>
        <div class="overlay-body">
          <p><strong>Name:</strong> {{selectedCandidate.candidateName}}</p>
          <p><strong>Education:</strong> {{selectedCandidate.degree}} - {{selectedCandidate.college}}</p>
          <p><strong>Metrics:</strong> {{selectedCandidate.cgpa}} CGPA</p>
          <p><strong>Skills:</strong> {{selectedCandidate.skills}}</p>
          <hr/>
          <a [href]="'http://localhost:8080/resumes/' + selectedCandidate.resumeFileName" target="_blank" class="cv-link">Download Full Resume (PDF)</a>
        </div>
      </div>
    </div>
  </div>
  `,
  styles: [`
    :host {
      --primary: #4f46e5;
      --primary-dark: #3730a3;
      --bg: #f8fafc;
      --card-bg: #ffffff;
