      --text-muted: #64748b;
      --border: #e2e8f0;
      --success: #10b981;
      --danger: #ef4444;
    }

    .dashboard-wrapper { background: var(--bg); min-height: 100vh; font-family: 'Inter', sans-serif; color: var(--text); }
    .main-header { background: white; padding: 0.75rem 2rem; display: flex; justify-content: space-between; align-items: center; border-bottom: 1px solid var(--border); position: sticky; top: 0; z-index: 100; }
    .logo-box { background: var(--primary); color: white; width: 32px; height: 32px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-weight: 800; }
    .header-brand { display: flex; align-items: center; gap: 12px; }
    .header-brand h1 { font-size: 1.1rem; font-weight: 800; margin: 0; }
    .badge-hr { background: #eef2ff; color: var(--primary); padding: 2px 8px; border-radius: 4px; font-size: 0.7rem; }
    .admin-name { font-weight: 600; font-size: 0.85rem; color: var(--text-muted); margin-right: 1.5rem; }
