    .scheduling-block { background: #f8fafc; padding: 1rem; border-radius: 10px; margin-top: 1.5rem; }
    .input-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-bottom: 10px; }
    .input-sm { padding: 8px; border: 1px solid var(--border); border-radius: 6px; font-size: 0.8rem; width: 100%; outline: none; }

    .btn-primary { background: var(--primary); color: white; border: none; padding: 10px 20px; border-radius: 8px; cursor: pointer; font-weight: 700; }
